args.sparql:
SELECT ?plant ?plantLabel ?amount ?inception WHERE {
  ?plant wdt:P31/wdt:P279* wd:Q159719 .
  ?plant p:P2109/ps:P2109 ?capacity_obj .
  ?capacity_obj wikibase:quantityAmount ?amount ;
                 wikibase:quantityUnit wd:Q71222 .
  ?plant wdt:P571 ?inception .
  ?plant rdfs:label ?plantLabel .
  FILTER(LANG(?plantLabel) = "en") .

  FILTER NOT EXISTS {
    ?other_plant wdt:P31/wdt:P279* wd:Q159719 .
    ?other_plant p:P2109/ps:P2109 ?other_capacity_obj .
    ?other_capacity_obj wikibase:quantityAmount ?other_amount ;
                         wikibase:quantityUnit wd:Q71222 .
    ?other_plant wdt:P571 ?other_inception .
    FILTER (?other_inception < ?inception && ?other_amount >= ?amount)
  }
}
ORDER BY DESC(?amount)
LIMIT 10
